// ─────────────────────────────────────────────
// UTILS
// ─────────────────────────────────────────────
function getCuota2026() {
  const m = new Date().getMonth() + 1;
  if (m <= 3) return 3000;
  if (m <= 6) return 3500;
  return 4000;
}
function getPeriodo2026() {
  const m = new Date().getMonth() + 1;
  if (m <= 3) return "Enero – Marzo";
  if (m <= 6) return "Abril – Junio";
  return "Julio en adelante";
}
function getCuotaYear(year, anualidades, settings) {
  if (anualidades[year]) return anualidades[year];
  if (settings.anualidades_futuras?.[year]) return settings.anualidades_futuras[year];
  return 4000;
}
function calcDeudaTotal(member, anualidades, pagos2026, settings) {
  if (member.tipo === "emérito" || member.tipo === "fundador") return 0;
  let total = 0;
  Object.entries(member.adeudos || {}).forEach(([yr, pagado]) => { if (!pagado) total += getCuotaYear(parseInt(yr), anualidades, settings); });
  const p = pagos2026[member.id];
  if (!p || p.status !== "verificado") total += getCuota2026();
  return total;
}
function calcDeudaPrevios(member, anualidades, settings) {
  if (member.tipo === "emérito" || member.tipo === "fundador") return 0;
  let total = 0;
  Object.entries(member.adeudos || {}).forEach(([yr, pagado]) => { if (!pagado) total += getCuotaYear(parseInt(yr), anualidades, settings); });
  return total;
}
function countAnualidadesAdeudo(member, pagos2026) {
  if (member.tipo === "emérito" || member.tipo === "fundador") return 0;
  const prev = Object.values(member.adeudos || {}).filter(v => !v).length;
  const p = pagos2026[member.id];
  return prev + (!p || p.status !== "verificado" ? 1 : 0);
}
function tieneAdeudosPrevios(member) {
  return Object.values(member.adeudos || {}).some(v => !v);
}
function fmt(n) { return `$${(n || 0).toLocaleString("es-MX")} MXN`; }
function fmtDate(iso) {
  if (!iso) return "—";
  return new Date(iso).toLocaleDateString("es-MX", { day: "2-digit", month: "short", year: "numeric", hour: "2-digit", minute: "2-digit" });
}

// ─────────────────────────────────────────────
// STORAGE
// ─────────────────────────────────────────────
// loadData/saveData now backed by Supabase config table (for settings/audit)
async function loadData(key, fallback) {
  try {
    const cfg = await db.getConfig();
    return cfg[key] ? JSON.parse(cfg[key]) : fallback;
  } catch { return fallback; }
}
async function saveData(key, value) {
  try { await db.setConfig(key, JSON.stringify(value)); } catch {}
}

